import React, { useState, useEffect } from 'react';
import { Boleto, fetchBoletosByCustomerId, marcarBoletoComoPago, gerarPixParaBoleto, gerarCarne } from '../../api/billing';

interface BillingTabProps {
    customerId: string;
}

export const BillingTab: React.FC<BillingTabProps> = ({ customerId }) => {
    const [boletos, setBoletos] = useState<Boleto[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [pixQrCode, setPixQrCode] = useState<string | null>(null);

    const loadBoletos = async () => {
        setLoading(true);
        setError(null);
        try {
            const data = await fetchBoletosByCustomerId(customerId);
            setBoletos(data);
        } catch (err) {
            setError('Falha ao carregar boletos.');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        loadBoletos();
    }, [customerId]);

    const handleMarcarPago = async (boletoId: string) => {
        await marcarBoletoComoPago(boletoId);
        loadBoletos();
    };

    const handleGerarPix = async (boletoId: string) => {
        const { qrCode } = await gerarPixParaBoleto(boletoId);
        setPixQrCode(qrCode);
        loadBoletos();
    };

    const handleGerarCarne = async (numParcelas: 6 | 12) => {
        await gerarCarne(customerId, numParcelas);
        loadBoletos();
    };

    if (loading) return <p>Carregando boletos...</p>;
    if (error) return <p style={{ color: '#b91c1c' }}>{error}</p>;

    return (
        <div style={{ display: 'grid', gap: '1rem' }}>
            <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap' }}>
                <button onClick={() => handleGerarCarne(6)}>Gerar Carnê (6 meses)</button>
                <button onClick={() => handleGerarCarne(12)}>Gerar Carnê (12 meses)</button>
            </div>
            {pixQrCode && (
                <div style={{ padding: '1rem', border: '1px solid #e2e8f0', borderRadius: 8, background: '#f8fafc' }}>
                    <h4 style={{ marginTop: 0 }}>PIX QR Code Gerado</h4>
                    <p style={{ color: '#475569' }}>Aponte a câmera do seu celular para o código abaixo ou copie a chave:</p>
                    <pre style={{ background: '#e2e8f0', padding: '0.75rem', borderRadius: 4, whiteSpace: 'pre-wrap', wordBreak: 'break-all' }}>{pixQrCode}</pre>
                    <button onClick={() => setPixQrCode(null)} style={{ marginTop: '0.5rem' }}>Fechar</button>
                </div>
            )}
            <table style={{ width: '100%', borderCollapse: 'collapse', background: '#fff', border: '1px solid #e2e8f0' }}>
                <thead>
                    <tr style={{ background: '#f1f5f9' }}>
                        <th style={{ padding: '0.6rem', textAlign: 'left' }}>ID</th>
                        <th style={{ padding: '0.6rem', textAlign: 'left' }}>Valor</th>
                        <th style={{ padding: '0.6rem', textAlign: 'left' }}>Vencimento</th>
                        <th style={{ padding: '0.6rem', textAlign: 'left' }}>Status</th>
                        <th style={{ padding: '0.6rem', textAlign: 'left' }}>Ações</th>
                    </tr>
                </thead>
                <tbody>
                    {boletos.map(boleto => (
                        <tr key={boleto.id}>
                            <td style={{ padding: '0.5rem 0.6rem', borderTop: '1px solid #e2e8f0' }}>{boleto.id}</td>
                            <td style={{ padding: '0.5rem 0.6rem', borderTop: '1px solid #e2e8f0' }}>R$ {boleto.amount.toFixed(2)}</td>
                            <td style={{ padding: '0.5rem 0.6rem', borderTop: '1px solid #e2e8f0' }}>{new Date(boleto.dueDate).toLocaleDateString()}</td>
                            <td style={{ padding: '0.5rem 0.6rem', borderTop: '1px solid #e2e8f0' }}>{boleto.status}</td>
                            <td style={{ padding: '0.5rem 0.6rem', borderTop: '1px solid #e2e8f0' }}>
                                <div style={{ display: 'flex', gap: '0.4rem', flexWrap: 'wrap' }}>
                                    {boleto.status === 'Pendente' && <button onClick={() => handleMarcarPago(boleto.id)}>Baixa Manual</button>}
                                    {boleto.status !== 'Pago' && <button onClick={() => handleGerarPix(boleto.id)}>Criar PIX</button>}
                                    <button>Enviar por Email</button>
                                </div>
                            </td>
                        </tr>
                    ))}
                     {boletos.length === 0 && (
                        <tr>
                            <td colSpan={5} style={{ padding: '1rem', textAlign: 'center', borderTop: '1px solid #e2e8f0', color: '#64748b' }}>
                                Nenhum boleto encontrado para este cliente.
                            </td>
                        </tr>
                    )}
                </tbody>
            </table>
        </div>
    );
};
